mapper.update:
INSERT INTO operating_account (stock_code, whole_qty)
VALUES (#{stockCode}, #{delta})
ON DUPLICATE KEY UPDATE whole_qty = whole_qty + #{delta}

mapper.select:
SELECT whole_qty
FROM operating_account
WHERE stock_code = #{stockCode}

mapper.update:
UPDATE operating_account
SET fractional_remainder = fractional_remainder + #{delta}
WHERE stock_code = #{stockCode}
  AND fractional_remainder + #{delta} >= 0

mapper.select:
SELECT fractional_remainder
FROM operating_account
WHERE stock_code = #{stockCode}
